import React, { useEffect, useState } from "react";
import * as api from "../utils/api";

export default function DoctorDashboard() {
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // Track which appointment is being edited: { id: 1, date: "...", time: "..." }
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({ date: "", time: "" });

  const u = JSON.parse(localStorage.getItem("user") || "null");

  useEffect(() => {
    if (!u || u.role !== "DOCTOR") { window.location.href = "/login"; return; }
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const doctors = await api.fetchDoctors();
      const doc = doctors.find(d => String(d.userId) === String(u.id));
      if (!doc) { setAppointments([]); setLoading(false); return; }
      const appts = await api.fetchAppointmentsByDoctor(doc.id);
      setAppointments(appts);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  const changeStatus = async (id, status) => {
    try {
      await api.setAppointmentStatus(id, status);
      setAppointments(a => a.map(x => x.id === id ? { ...x, status } : x));
    } catch (err) { alert("Failed: " + (err.message || err)); }
  };

  // ✅ Start Edit Mode
  const startEdit = (appt) => {
    setEditingId(appt.id);
    setEditForm({ 
      date: appt.appointmentDate || "", 
      time: appt.appointmentTime || "" 
    });
  };

  // ✅ Save Changes
  const saveEdit = async (id) => {
    try {
      await api.updateAppointment(id, {
        appointmentDate: editForm.date,
        appointmentTime: editForm.time
      });
      alert("Rescheduled!");
      setEditingId(null);
      loadData(); // Reload to see changes
    } catch (err) {
      alert("Failed to update: " + err.message);
    }
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div style={{ maxWidth:900, margin:"20px auto", padding:12 }}>
      <h2>Doctor Dashboard</h2>
      {appointments.length === 0 && <div>No appointments.</div>}
      
      {appointments.map(a => (
        <div key={a.id} style={{border:"1px solid #ddd", padding:16, marginBottom:12, borderRadius:8, background:"#fff"}}>
          
          <div style={{marginBottom:8}}>
            <strong>Patient:</strong> {a.patientName || a.patientId} <br/>
            <strong>Reason:</strong> {a.reason}
          </div>

          {/* EDIT MODE TOGGLE */}
          {editingId === a.id ? (
            <div style={{ background: "#f9f9f9", padding: 10, borderRadius: 6 }}>
              <div style={{ marginBottom: 5 }}>
                <label>New Date: </label>
                <input type="date" value={editForm.date} onChange={e=>setEditForm({...editForm, date: e.target.value})} />
              </div>
              <div style={{ marginBottom: 5 }}>
                <label>New Time: </label>
                <input type="time" value={editForm.time} onChange={e=>setEditForm({...editForm, time: e.target.value})} />
              </div>
              <button onClick={() => saveEdit(a.id)} style={{ marginRight: 8, background:"#000", color:"#fff", border:"none", padding:"6px 12px", borderRadius:4, cursor:"pointer" }}>Save</button>
              <button onClick={() => setEditingId(null)} style={{ background:"transparent", border:"1px solid #999", padding:"6px 12px", borderRadius:4, cursor:"pointer" }}>Cancel</button>
            </div>
          ) : (
            <div>
               <strong>Time:</strong> {a.appointmentDate} at {a.appointmentTime}
               <button onClick={() => startEdit(a)} style={{ marginLeft: 12, fontSize: "12px", cursor: "pointer" }}>✏️ Reschedule</button>
            </div>
          )}

          <div style={{marginTop:12, borderTop:"1px solid #eee", paddingTop:8}}>
            <strong>Status:</strong> {a.status}
            <div style={{marginTop:8}}>
               <button onClick={() => changeStatus(a.id, "APPROVED")} disabled={a.status === "APPROVED"} style={{marginRight:8}}>Accept</button>
               <button onClick={() => changeStatus(a.id, "REJECTED")} disabled={a.status === "REJECTED"}>Reject</button>
            </div>
          </div>

        </div>
      ))}
    </div>
  );
}
